var body = $json.body || $json;
var specText = body.specificationText || body.fullText || '';
if (specText.length > 80000) specText = specText.substring(0, 80000);
return [{ json: { specText: specText } }];

// Sanitize Unicode smart quotes that break JSON parsing
function sanitize(s) {
  return s.replace(/[\u201C\u201D\u201E\u201F\u00AB\u00BB\u2018\u2019]/g, "'");
}

function tryParse(s) {
  try { return JSON.parse(s); } catch(e) { return null; }
}

function extractJson(s) {
  var m = s.match(/```(?:json)?\s*([\s\S]*?)```/);
  var c = m ? m[1].trim() : s;
  var start = c.indexOf('{');
  var end = c.lastIndexOf('}');
  if (start === -1 || end === -1) {
    // Try array
    start = c.indexOf('[');
    end = c.lastIndexOf(']');
    if (start === -1 || end === -1) return s;
  }
  return c.substring(start, end + 1);
}

function fixCommon(s) {
  return s.replace(/,\s*([\]\}])/g, '$1');
}

function fixQuotes(s) {
  var out = '';
  var inStr = false;
  var escaped = false;
  for (var i = 0; i < s.length; i++) {
    var ch = s[i];
    if (escaped) { out += ch; escaped = false; continue; }
    if (ch === '\\') { out += ch; escaped = true; continue; }
    if (ch === '"') {
      if (!inStr) {
        inStr = true;
        out += ch;
      } else {
        var rest = s.substring(i + 1).trimStart();
        var next = rest.length > 0 ? rest[0] : '';
        if (next === ':' || next === ',' || next === '}' || next === ']' || rest.length === 0) {
          inStr = false;
          out += ch;
        } else {
          out += '\\"';
        }
      }
    } else {
      out += ch;
    }
  }
  return out;
}

var raw = ($json.text || $json.response || '').trim();
var result = null;

raw = sanitize(raw);

result = tryParse(raw);

if (!result) {
  var extracted = fixCommon(extractJson(raw));
  result = tryParse(extracted);
}

if (!result) {
  var extracted2 = fixCommon(extractJson(raw));
  result = tryParse(fixQuotes(extracted2));
}

if (!result) {
  result = {
    project_type: 'unknown',
    technical_parameters: [],
    key_quantities: [],
    _raw: raw.substring(0, 5000),
    _parse_error: true
  };
}

return [{ json: { specData: result } }];
